# Domain models for a simple employee management system

class Employee:
    name: str
    id: int

    def __init__(self, name: str, id: int):
        self.name = name
        self.id = id

    @virtual
    def get_info(self) -> str:
        return f"Employee {self.name} (ID: {self.id})"

    @virtual
    def calculate_bonus(self) -> float:
        return 1000.0

class Manager(Employee):
    team_size: int

    def __init__(self, name: str, id: int, team_size: int):
        super().__init__(name, id)
        self.team_size = team_size

    @override
    def get_info(self) -> str:
        return f"Manager {self.name} (ID: {self.id}, Team: {self.team_size})"

    @override
    def calculate_bonus(self) -> float:
        return 1000.0 + (self.team_size * 200.0)

class Developer(Employee):
    programming_language: str

    def __init__(self, name: str, id: int, language: str):
        super().__init__(name, id)
        self.programming_language = language

    @override
    def get_info(self) -> str:
        return f"Developer {self.name} (ID: {self.id}, Lang: {self.programming_language})"

    @override
    def calculate_bonus(self) -> float:
        return 1500.0

