# Payroll processing utilities
from models import Employee, Manager, Developer

class PayrollProcessor:
    total_bonus: float

    def __init__(self):
        self.total_bonus = 0.0

    def process_employee(self, emp: Employee) -> None:
        bonus: float = emp.calculate_bonus()
        self.total_bonus += bonus

    def get_total(self) -> float:
        return self.total_bonus
